// Initialize scrollspy and smooth scrolling
(function($) {
  "use strict";
  // Smooth scrolling for scroll triggers (native, no easing plugin needed)
  $('a.js-scroll-trigger[href*="#"]:not([href="#"])').click(function() {
    if (location.pathname.replace(/^\//, '') == this.pathname.replace(/^\//, '') && location.hostname == this.hostname) {
      var target = $(this.hash);
      target = target.length ? target : $('[name=' + this.hash.slice(1) + ']');
      if (target.length) {
        target[0].scrollIntoView({ behavior: 'smooth' });
        return false;
      }
    }
  });
  
  // Close responsive menu when a scroll trigger link is clicked
  $('.js-scroll-trigger').click(function() {
    $('.navbar-collapse').collapse('hide');
  });
  
  // Activate scrollspy
  $('body').scrollspy({
    target: '#sideNav',
    offset: 54
  });
})(jQuery);

// Multi-theme system
function setTheme(themeName) {
  if (themeName) {
    document.body.setAttribute('data-theme', themeName);
  } else {
    document.body.removeAttribute('data-theme');
  }
  localStorage.setItem('portfolio-theme', themeName || '');

  document.querySelectorAll('.swatch').forEach(function(s) {
    var t = s.getAttribute('data-theme') || '';
    s.classList.toggle('active', t === (themeName || ''));
  });
}

function initializeTheme() {
  var saved = localStorage.getItem('portfolio-theme') || '';
  // Migrate old "dark" key → amber
  if (saved === 'dark' || saved === 'light') saved = saved === 'dark' ? 'amber' : '';
  setTheme(saved);
}

document.addEventListener('DOMContentLoaded', function() {
  initializeTheme();
  document.querySelectorAll('.swatch').forEach(function(swatch) {
    swatch.addEventListener('click', function() {
      setTheme(this.getAttribute('data-theme') || '');
    });
  });
});